    '岩_水热_1': { name: '钟摆时间酒', desc: '饮用后，你的时间感会在快与慢之间摇摆不定，仿佛心中有座看不见的钟摆。' },
    '岩_水热_2': { name: '风筝缓落油', desc: '在持续时间内，你下落的速度会显著减慢，仿佛被一只看不见的风筝牵着。' },
    '岩_水热_3': { name: '共鸣情绪烟香', desc: '点燃后，吸入者会共享彼此的情绪波动，喜怒如同同一颗心脏跳动。' },
    '岩_水热_4': { name: '枯骨召令精华', desc: '倒在骷髅之上后，它会重新站起，并在十三天内听从你的命令。' },
    '岩_水热_5': { name: '枯荣循环油膏', desc: '涂抹于土地后，植物会迅速生长至繁茂顶点，随后在数分钟内枯萎。' },
    '岩_水热_6': { name: '轻厄试管', desc: '在持续时间内，你的小概率遭遇轻微倒霉，例如鞋带自行松开或笔尖断裂。' },
    '岩_水热_7': { name: '石铃结晶瓶', desc: '你敲击过的石头会记住你的节奏，并在数分钟后自行重复那段韵律。' },
