// 2. 状态管理

let currentIngredients = {
    '盔瓣蛛兰': 0,
    '水冬藻': 0,
    '北落花烛': 0,
    '锻叶冬青': 0
};

// 相图缓存
const phaseDiagrams = {};
// 预加载相图
const PHASE_IMAGES = {
    '水岩': 'data:image/png;base64,',
    '水热': 'data:image/png;base64,',
    '水电': 'data:image/png;base64,',
    '热岩': 'data:image/png;base64,',
    '热电': 'data:image/png;base64,',
    '电岩': 'data:image/png;base64,',
};

// 相图颜色映射 (按 Hue 排序，对应 ID 1-10)
const PHASE_COLORS = [
    "#DB4541", "#DB9841", "#DBCD41", "#9ADB41", "#41DB96", 
    "#41B0DB", "#416CDB", "#5441DB", "#A241DB", "#DB41DA"
];

let history = [];

// 3. UI 初始化

document.addEventListener('DOMContentLoaded', () => {
    loadPhaseDiagrams();
    initIngredientList();
    initDebugPanel();
    
    document.getElementById('brew-btn').addEventListener('click', brewPotion);
    document.getElementById('history-search').addEventListener('input', filterHistory);
    
    initPokedex();
    initMobileInteractions();
});

function initMobileInteractions() {
    // 1. Ingredient Icon Click (Toggle Controls)
    // We need to use event delegation or attach to existing elements
    // Since initIngredientList runs before this, elements exist.
    const icons = document.querySelectorAll('.ingredient-icon');
    icons.forEach(icon => {
        icon.addEventListener('click', (e) => {
            // Only effective on mobile (check width or just let CSS handle display)
            if (window.innerWidth > 768) return;
            
            e.stopPropagation(); // Prevent document click from closing immediately
            
            const item = icon.closest('.ingredient-item');
            
            // Close others
            document.querySelectorAll('.ingredient-item.mobile-expanded').forEach(other => {
                if (other !== item) other.classList.remove('mobile-expanded');
            });
            
            item.classList.toggle('mobile-expanded');
        });
    });

    // Close ingredient controls when clicking outside
    document.addEventListener('click', () => {
        if (window.innerWidth <= 768) {
            document.querySelectorAll('.ingredient-item.mobile-expanded').forEach(item => {
                item.classList.remove('mobile-expanded');
            });
        }
    });

    // Prevent clicks inside controls from closing
    document.querySelectorAll('.ingredient-controls').forEach(ctrl => {
        ctrl.addEventListener('click', (e) => {
            e.stopPropagation();
        });
    });

    // 2. History Sidebar Toggle
    const historyCol = document.getElementById('history-column');
    const collapsedView = document.querySelector('.mobile-history-collapsed');
    const closeBtn = document.getElementById('close-history-btn');

    if (collapsedView) {
        collapsedView.addEventListener('click', () => {
            historyCol.classList.add('expanded');
        });
    }

    if (closeBtn) {
        closeBtn.addEventListener('click', () => {
            historyCol.classList.remove('expanded');
        });
    }
}

function loadPhaseDiagrams() {
    Object.entries(PHASE_IMAGES).forEach(([name, src]) => {
        const img = new Image();
        img.src = src;
        img.onload = () => {
            // 创建隐藏Canvas并绘制图片，以便后续读取像素
            const canvas = document.createElement('canvas');
            canvas.width = img.width;
            canvas.height = img.height;
            const ctx = canvas.getContext('2d');
            ctx.drawImage(img, 0, 0);
            phaseDiagrams[name] = {
                canvas: canvas,
                ctx: ctx,
                width: img.width,
                height: img.height
            };
            console.log(`Loaded phase diagram: ${name}`);
        };
        img.onerror = () => {
            console.error(`Failed to load phase diagram: ${name}`);
        };
    });
}

function initIngredientList() {
    const listContainer = document.getElementById('ingredient-list');
    listContainer.innerHTML = '';
    
    Object.keys(INGREDIENTS).forEach(name => {
        const item = document.createElement('div');
        item.className = 'ingredient-item';
        
        const data = INGREDIENTS[name];
        
        item.innerHTML = `
            <div class="ingredient-icon">${data.icon}</div>
            <div class="ingredient-info">
                <span class="ingredient-name">${name}</span>
                <span class="ingredient-count">当前: <span id="count-${name}">0</span> 份</span>
            </div>
            <div class="ingredient-controls">
                <button onclick="addIngredient('${name}', -1)">-1</button>
                <button onclick="addIngredient('${name}', 1)">+1</button>
                <button onclick="addIngredient('${name}', 10)">+10</button>
                <button onclick="clearIngredient('${name}')">清空</button>
            </div>
        `;
        listContainer.appendChild(item);
    });
}

function initDebugPanel() {
    if (typeof ADMIN !== 'undefined' && ADMIN) {
        document.getElementById('debug-panel').classList.remove('hidden');
    }
}

// 4. 交互函数

window.addIngredient = function(name, amount) {
    if (currentIngredients[name] + amount > 100) {
        currentIngredients[name] = 100;
    } else if (currentIngredients[name] + amount < 0) {
        currentIngredients[name] = 0;
    } else {
        currentIngredients[name] += amount;
    }
    updateIngredientDisplay(name);
};

window.clearIngredient = function(name) {
    currentIngredients[name] = 0;
    updateIngredientDisplay(name);
};

function updateIngredientDisplay(name) {
    document.getElementById(`count-${name}`).innerText = currentIngredients[name];
}

function showMessage(msg, isError = false, desc = '') {
    const el = document.getElementById('message-area');
    
    if (!msg) {
        el.innerHTML = '';
        el.className = ''; // Clear all classes
        return;
    }

    el.classList.add('has-message');

    if (desc) {
        el.innerHTML = `<div class="message-title">${msg}</div><div class="message-desc">${desc}</div>`;
    } else {
        el.innerText = msg;
    }
    
    // Remove old classes
    el.classList.remove('error', 'success');
    
    // Add new class based on isError
    if (isError) {
        el.classList.add('error');
        el.style.color = '#d32f2f'; // Fallback
    } else {
        el.classList.add('success');
        el.style.color = '#388e3c'; // Fallback
    }
}

// 5. 核心炼药逻辑

function brewPotion() {
    showMessage('');
    
    // 1. 统计非零药材
    let activeIngredients = Object.entries(currentIngredients)
        .filter(([_, count]) => count > 0)
        .map(([name, count]) => ({ 
            name, 
            attr: INGREDIENTS[name].attr, 
            count 
        }));
    
    // 生成药材记录文本 (基于初始输入)
    const ingredientsText = activeIngredients
        .map(i => `${i.name} x${i.count}`)
        .join(', ');

    const count = activeIngredients.length;
    
    // 2. 数量验证
    if (count === 0) {
        showMessage('锅里是空的。', true);
        return;
    }
    
    if (count === 1) {
        showMessage(`你把${activeIngredients[0].name}煮成了汤……`, true);
        addToHistory('失败', `你把${activeIngredients[0].name}煮成了汤……`, true, ingredientsText);
        return;
    }
    
    if (count === 2) {
        showMessage('剧烈的药性冲突让这锅药不适合任何人饮用。', true);
        addToHistory('失败', '剧烈的药性冲突让这锅药不适合任何人饮用。', true, ingredientsText);
        return;
    }
    
    // 3种药材：补齐第4种 (0.5份)
    if (count === 3) {
        const allNames = Object.keys(INGREDIENTS);
        const activeNames = activeIngredients.map(i => i.name);
        const missingName = allNames.find(n => !activeNames.includes(n));
        
        // 注意：这里我们创建一个新的计算用对象，不修改UI显示的份数
        activeIngredients.push({
            name: missingName,
            attr: INGREDIENTS[missingName].attr,
            count: 0.5
        });
    }
    
    // 此时 activeIngredients 应该有 4 个元素 (原生的4个 或 补齐后的4个)
    // 按份数排序 (从大到小)
    activeIngredients.sort((a, b) => b.count - a.count);
    
    // 3. 元素判定
    
    // 第一元素 (Max)
    const first = activeIngredients[0];
    const second = activeIngredients[1];
    const third = activeIngredients[2];
    const fourth = activeIngredients[3]; // 单位元素
    
    // 检查第一元素是否有并列
    if (first.count === second.count) {
        showMessage('药性冲突，药剂无效。', true);
        addToHistory('失败', '药性冲突，药剂无效。', true, ingredientsText);
        return;
    }
    
    // 检查第三、第四是否相等 (药性混乱)
    // 修正逻辑：题目要求“无法找到第二、第三高的药剂”时无效。
    // 如果 2==3，是合法的。
    // 如果 3==4，则无法区分谁是第三谁是单位元素（或者说前三名确定后，剩下的就是单位元素，但如果并列第3，则无法确定唯一单位元素？）
    // 题目原话：“如果第三、第四高的药剂份数相等（无法找到第二、第三高的药剂）：药性混乱，药剂无效。”
    if (third.count === fourth.count) {
        showMessage('药性混乱，药剂无效。', true);
        addToHistory('失败', '药性混乱，药剂无效。', true, ingredientsText);
        return;
    }
    
    // 检查主药性是否充足 (First > Second + Third)
    if (first.count <= second.count + third.count) {
        showMessage('主药性不足，药剂无效。', true);
        addToHistory('失败', '主药性不足，药剂无效。', true, ingredientsText);
        return;
    }
    
    // 4. 相图逻辑
    
    // 确定相图类型：由第二和第三元素组成。
    // 题目：相图名字包含两个字，第一个对应横轴，第二个对应纵轴。
    // 我们需要确定用 "Attr2Attr3" 还是 "Attr3Attr2"？
    // 假设：CSV中的相图类型就是存在的相图。例如 "热岩"。
    // 我们需要检查 POTION_DB 中是否存在对应的键。
    // 组合可能是：第二+第三 或 第三+第二。
    
    let phaseType = `${second.attr}${third.attr}`;
    let xAttr = second.attr;
    let yAttr = third.attr;
    let xCount = second.count;
    let yCount = third.count;
    
    // 简单的存在性检查：如果 POTION_DB 中有以 "First_SecondThird_" 开头的键，说明顺序是 SecondThird
    // 否则尝试 ThirdSecond
    // 但我们的 POTION_DB 键是完整匹配的。
    // 我们可以硬编码相图的合法组合。根据CSV，存在的组合有：
    // 电主属性: 热岩, 水热, 水岩
    // 热主属性: 电岩, 水电, 水岩
    // 水主属性: 电岩, 热电, 热岩
    // 岩主属性: 热电, 水电, 水热
    
    // 让我们检测一下合法的 PhaseType
    const validPhaseTypes = [
        '热岩', '水热', '水岩', 
        '电岩', '水电', 
        '热电'
    ]; 
    // 注意：CSV里有 "水热" 也有 "热水" 吗？
    // 查看CSV:
    // 电: 热岩, 水热, 水岩
    // 热: 电岩, 水电, 水岩
    // 水: 电岩, 热电, 热岩
    // 岩: 热电, 水电, 水热
    // 似乎顺序是固定的？比如总是 "热岩" 而没有 "岩热"？
    // 让我们再次检查 CSV 内容。
    // Line 1: 电,热岩 -> 热岩
    // Line 30: 热,电岩 -> 电岩
    // Line 55: 水,电岩 -> 电岩
    // Line 83: 岩,热电 -> 热电
    
    // 看来相图名字是固定的组合。我们需要找到匹配的那个。
    let diagramName = null;
    if (hasPotionEntry(first.attr, second.attr + third.attr)) {
        diagramName = second.attr + third.attr;
        xAttr = second.attr; yAttr = third.attr;
        xCount = second.count; yCount = third.count;
    } else if (hasPotionEntry(first.attr, third.attr + second.attr)) {
        diagramName = third.attr + second.attr;
        xAttr = third.attr; yAttr = second.attr;
        xCount = third.count; yCount = second.count;
    } else {
        // 理论上不应该发生，除非CSV数据缺失
        console.error("Unknown phase diagram for", second.attr, third.attr);
        showMessage('未知的相图组合。', true);
        return;
    }

    // 计算坐标
    // X = X轴属性份数 / 单位元素份数
    // Y = Y轴属性份数 / 单位元素份数
    const unitCount = fourth.count;
    if (unitCount === 0) {
        // 理论上不可能，因为至少有0.5
        showMessage('单位元素为0，无法计算。', true);
        return;
    }
    
    // 坐标范围：相图是 100x100。
    // 比例大于1。
    // 假设比例直接映射到坐标？比如 比例 1.5 -> 坐标 ?
    // 题目说：“得到两个大于1的...比例。根据这两个比例生成坐标，在相图上找到对应的点。”
    // 通常相图坐标可能是 0-100。如果比例是 2.5，坐标是 25？还是说比例本身就是坐标？
    // 考虑到“左下(0,0), 右上(100,100)”，且比例 > 1。
    // 如果比例可以是 10, 20... 那么直接作为坐标比较合理。
    // 如果比例是 1.2, 1.5... 那么可能需要乘以某个系数。
    // 让我们假设：坐标 = 比例 * 10 (例如 比例5 -> 坐标50)。或者 坐标 = 比例。
    // 考虑到份数最大100，最小0.5。最大比例 200。
    // 如果坐标直接是比例，那么 >100 就越界了。
    // 让我们设定：坐标 = 比例 * 10。这样 1.0 -> 10, 10.0 -> 100。
    // 如果比例 > 10，则越界。
    // 这似乎是一个合理的假设。
    
    let rawX = xCount / unitCount;
    let rawY = yCount / unitCount;
    
    // 缩放系数：假设比例 1~10 对应坐标 0~100 (即 x10)
    // 或者题目有隐含意思。
    // 暂定 x10。
    let coordX = Math.floor(rawX * 10);
    let coordY = Math.floor(rawY * 10);
    
    // 5. 采样与结果
    
    // 检查边界
    if (coordX < 0 || coordX > 100 || coordY < 0 || coordY > 100) {
        showMessage('药性不稳定，药剂无效。', true);
        if (ADMIN) updateDebugPanel(diagramName, coordX, coordY, '#000000', xAttr, yAttr);
        addToHistory('失败', '药性不稳定', true, ingredientsText);
        return;
    }
    
    // 采样颜色
    const color = getPhaseDiagramColor(diagramName, coordX, coordY);
    
    // 检查黑色 (边界)
    if (isBlack(color)) {
        showMessage('药性模糊，药剂无效。', true);
        if (ADMIN) updateDebugPanel(diagramName, coordX, coordY, color, xAttr, yAttr);
        addToHistory('失败', '药性模糊', true, ingredientsText);
        return;
    }
    
    // 获取效果 ID
    const effectID = getEffectIDFromColor(color);
    
    // 查找最终药剂
    const potionKey = `${first.attr}_${diagramName}_${effectID}`;
    const potion = POTION_DB[potionKey];
    
    if (ADMIN) updateDebugPanel(diagramName, coordX, coordY, color, xAttr, yAttr);
    
    if (potion) {
        showMessage(`炼制成功：${potion.name}`, false, potion.desc);
        addToHistory(potion.name, potion.desc, false, ingredientsText);
        unlockPotion(potionKey);
    } else {
        showMessage('未知药剂 (查无此配方)', true);
        addToHistory('失败？', '不存在的效果', true, ingredientsText);
    }
}

// 辅助：检查是否存在该主属性+相图的配方
function hasPotionEntry(primary, diagram) {
    // 只要有一个 effectID 存在即可
    return POTION_DB[`${primary}_${diagram}_1`] !== undefined;
}

// 模拟相图采样
// 为了简单，我们使用程序化生成的颜色
// 我们需要确保整个 100x100 区域能覆盖到 1-10 的所有 Effect ID
// 我们可以根据 (x, y) 坐标生成一个 Hue
function getPhaseDiagramColor(diagramName, x, y) {
    const diagram = phaseDiagrams[diagramName];
    if (!diagram) {
        console.warn(`Phase diagram ${diagramName} not loaded yet or invalid.`);
        return 'hsl(0, 0%, 0%)'; // Default black
    }
    
    // 映射坐标
    // 输入 x, y 是 0-100
    // 图片坐标:
    // pixelX = (x / 100) * width
    // pixelY = ((100 - y) / 100) * height  (注意 Y 轴翻转)
    
    // 防止越界
    let pixelX = Math.floor((x / 100) * diagram.width);
    let pixelY = Math.floor(((100 - y) / 100) * diagram.height);
    
    if (pixelX >= diagram.width) pixelX = diagram.width - 1;
    if (pixelY >= diagram.height) pixelY = diagram.height - 1;
    if (pixelX < 0) pixelX = 0;
    if (pixelY < 0) pixelY = 0;
    
    const pixelData = diagram.ctx.getImageData(pixelX, pixelY, 1, 1).data;
    // pixelData is [r, g, b, a]
    
    return `rgb(${pixelData[0]}, ${pixelData[1]}, ${pixelData[2]})`;
}

function isBlack(color) {
    const match = color.match(/rgb\((\d+),\s*(\d+),\s*(\d+)\)/);
    if (!match) return true;
    
    const r = parseInt(match[1]);
    const g = parseInt(match[2]);
    const b = parseInt(match[3]);
    
    // Check if color is close to any of the valid phase colors
    let minDist = Infinity;
    for (const hex of PHASE_COLORS) {
        const tr = parseInt(hex.slice(1, 3), 16);
        const tg = parseInt(hex.slice(3, 5), 16);
        const tb = parseInt(hex.slice(5, 7), 16);
        const dist = Math.sqrt(Math.pow(r - tr, 2) + Math.pow(g - tg, 2) + Math.pow(b - tb, 2));
        if (dist < minDist) minDist = dist;
    }
    
    // If distance to nearest valid color is large, treat as black/background
    return minDist > 60;
}

function getEffectIDFromColor(colorStr) {
    const match = colorStr.match(/rgb\((\d+),\s*(\d+),\s*(\d+)\)/);
    if (!match) return 1;
    
    const r = parseInt(match[1]);
    const g = parseInt(match[2]);
    const b = parseInt(match[3]);
    
    let minDist = Infinity;
    let closestIndex = 0;
    
    for (let i = 0; i < PHASE_COLORS.length; i++) {
        const hex = PHASE_COLORS[i];
        const tr = parseInt(hex.slice(1, 3), 16);
        const tg = parseInt(hex.slice(3, 5), 16);
        const tb = parseInt(hex.slice(5, 7), 16);
        
        const dist = Math.sqrt(Math.pow(r - tr, 2) + Math.pow(g - tg, 2) + Math.pow(b - tb, 2));
        if (dist < minDist) {
            minDist = dist;
            closestIndex = i;
        }
    }
    
    return closestIndex + 1;
}

function addToHistory(title, desc, isError = false, ingredientsText = '') {
    const list = document.getElementById('history-list');
    const card = document.createElement('div');
    card.className = `history-card ${isError ? 'error' : ''}`;
    card.innerHTML = `
        <div class="history-title">${title}</div>
        ${ingredientsText ? `<div class="history-ingredients">${ingredientsText}</div>` : ''}
        <div class="history-desc">${desc}</div>
        <div class="history-meta">${new Date().toLocaleTimeString()}</div>
    `;
    // 插入到最前面
    list.insertBefore(card, list.firstChild);
    
    history.push({ title, desc, isError, ingredientsText });

    // Update Mobile Preview
    updateHistoryPreview(title, isError);
}

function updateHistoryPreview(title, isError) {
    const preview = document.getElementById('history-preview');
    if (!preview) return;

    const item = document.createElement('div');
    item.className = 'history-preview-item';
    item.innerText = title;
    if (isError) item.style.color = '#d32f2f';

    // Insert at top
    preview.insertBefore(item, preview.firstChild);

    // Keep only last 5
    while (preview.children.length > 5) {
        preview.removeChild(preview.lastChild);
    }
}

function filterHistory() {
    const query = document.getElementById('history-search').value.toLowerCase();
    const cards = document.querySelectorAll('.history-card');
    
    cards.forEach(card => {
        const text = card.innerText.toLowerCase();
        if (text.includes(query)) {
            card.style.display = 'block';
        } else {
            card.style.display = 'none';
        }
    });
}

function updateDebugPanel(name, x, y, color, xAttr, yAttr) {
    document.getElementById('debug-phase-name').innerText = name;
    document.getElementById('debug-x').innerText = x;
    document.getElementById('debug-y').innerText = y;
    document.getElementById('debug-color').innerText = color;
    document.getElementById('debug-color').style.color = color;
    
    // 更新轴标签
    if (xAttr) document.getElementById('debug-x-label').innerText = xAttr;
    if (yAttr) document.getElementById('debug-y-label').innerText = yAttr;
    
    // 绘制简易相图预览
    const container = document.getElementById('debug-canvas-container');
    container.innerHTML = '';
    const canvas = document.createElement('canvas');
    canvas.width = 100;
    canvas.height = 100;
    canvas.style.border = '1px solid white';
    const ctx = canvas.getContext('2d');
    
    // 绘制背景 (模拟相图)
    // 步长改为 2 以提高精度
    const step = 2;
    for (let i = 0; i < 100; i+=step) {
        for (let j = 0; j < 100; j+=step) {
            ctx.fillStyle = getPhaseDiagramColor(name, i, j);
            // 坐标系翻转: 逻辑坐标 (i, j) -> Canvas坐标 (i, 100 - j - step)
            // j=0 (底部) -> Canvas Y = 100 - 0 - 2 = 98 (画在最底部2像素)
            ctx.fillRect(i, 100 - j - step, step, step); 
        }
    }
    
    // 绘制点
    ctx.fillStyle = 'white';
    ctx.strokeStyle = 'black';
    ctx.lineWidth = 1.5;
    ctx.beginPath();
    // 绘制点时，也需要将逻辑坐标 y 翻转为 canvas 坐标
    // 逻辑 y (0-100) -> Canvas Y (100 - 0)
    // 注意：上面的循环绘制是 100x100 的模拟。这里的 (x, y) 是 0-100 的逻辑坐标。
    // Canvas 大小是 100x100。
    // 所以 Canvas Y = 100 - y
    ctx.arc(x, 100 - y, 4, 0, Math.PI * 2);
    ctx.fill();
    ctx.stroke();
    
    container.appendChild(canvas);
}

// --- Pokedex Logic ---

let unlockedPotions = new Set();
const TOTAL_POTIONS = 110;

// 初始化图鉴
function initPokedex() {
    const saved = localStorage.getItem('unlockedPotions');
    if (saved) {
        unlockedPotions = new Set(JSON.parse(saved));
    }
    updatePokedexProgress();

    // 绑定事件
    const pokedexBtn = document.getElementById('pokedex-btn');
    if (pokedexBtn) pokedexBtn.addEventListener('click', openPokedex);
    
    const closeBtn = document.getElementById('close-pokedex-btn');
    if (closeBtn) closeBtn.addEventListener('click', closePokedex);
    
    const clearBtn = document.getElementById('clear-pokedex-btn');
    if (clearBtn) clearBtn.addEventListener('click', clearPokedex);
    
    // 点击模态框外部关闭
    window.addEventListener('click', (event) => {
        const modal = document.getElementById('pokedex-modal');
        if (event.target === modal) {
            closePokedex();
        }
    });
}

// 解锁药剂
function unlockPotion(potionKey) {
    if (!unlockedPotions.has(potionKey)) {
        unlockedPotions.add(potionKey);
        localStorage.setItem('unlockedPotions', JSON.stringify([...unlockedPotions]));
        updatePokedexProgress();
    }
}

// 更新进度显示
function updatePokedexProgress() {
    const progressEl = document.getElementById('pokedex-progress');
    if (progressEl) {
        progressEl.innerText = `(${unlockedPotions.size}/${TOTAL_POTIONS})`;
    }
}

// 打开图鉴
function openPokedex() {
    const modal = document.getElementById('pokedex-modal');
    const grid = document.getElementById('pokedex-grid');
    grid.innerHTML = ''; // 清空现有内容

    // 遍历所有药剂
    // POTION_DB 的键是无序的，我们最好按顺序显示
    // 顺序：电(10) -> 热(10) ...
    // 我们先获取所有键并排序
    // 排序规则：主属性 -> 相图 -> ID
    const keys = Object.keys(POTION_DB).sort((a, b) => {
        const partsA = a.split('_');
        const partsB = b.split('_');
        
        // 主属性顺序：电、热、水、岩
        const attrOrder = { '电': 1, '热': 2, '水': 3, '岩': 4 };
        if (attrOrder[partsA[0]] !== attrOrder[partsB[0]]) {
            return attrOrder[partsA[0]] - attrOrder[partsB[0]];
        }
        
        // 相图顺序 (字母序即可)
        if (partsA[1] !== partsB[1]) {
            return partsA[1].localeCompare(partsB[1]);
        }
        
        // ID 顺序
        return parseInt(partsA[2]) - parseInt(partsB[2]);
    });

    keys.forEach(key => {
        const potion = POTION_DB[key];
        const isUnlocked = unlockedPotions.has(key);
        
        const card = document.createElement('div');
        card.className = `pokedex-card ${isUnlocked ? 'unlocked' : 'locked'}`;
        
        const name = isUnlocked ? potion.name : '???';
        const desc = isUnlocked ? potion.desc : '';
        
        card.innerHTML = `
            <div class="pokedex-card-title">${name}</div>
            <div class="pokedex-card-desc">${desc}</div>
        `;
        
        grid.appendChild(card);
    });

    modal.classList.remove('hidden');
}

// 关闭图鉴
function closePokedex() {
    document.getElementById('pokedex-modal').classList.add('hidden');
}

// 清空图鉴
function clearPokedex() {
    if (confirm('确定要清空图鉴记录吗？此操作无法撤销。')) {
        unlockedPotions.clear();
        localStorage.removeItem('unlockedPotions');
        updatePokedexProgress();
        openPokedex(); // 刷新显示
    }
}

